const express = require('express');
const axios = require('axios');
require('dotenv').config();

const app = express();
const PORT = 3000;

// Middleware to parse JSON bodies
app.use(express.json());

// POST /api/wallet/create - Create wallet with Prembly NIN verification
app.post('/api/wallet/create', async (req, res) => {
  try {
    const { ninNumber, faceLivelinessRef } = req.body;

    // Validate required fields
    if (!ninNumber) {
      return res.status(400).json({
        error: 'ninNumber is required'
      });
    }

    // Get credentials from environment variables
    const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
    const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

    if (!PREMBLY_APP_ID || !PREMBLY_API_KEY) {
      return res.status(500).json({
        error: 'Server configuration error: Prembly credentials not configured'
      });
    }

    // Call Prembly NIN verification API
    const premblyResponse = await axios.post(
      'https://api.prembly.com/verification/nin',
      {
        number: ninNumber
      },
      {
        headers: {
          'app-id': PREMBLY_APP_ID,
          'x-api-key': PREMBLY_API_KEY,
          'Content-Type': 'application/json'
        }
      }
    );

    // Check if verification was successful
    if (premblyResponse.data && premblyResponse.data.status === 'success') {
      // Generate a new wallet ID (in production, this would be created in your database)
      const walletId = `new_wallet_${Date.now()}`;

      return res.status(201).json({
        wallet_id: walletId
      });
    } else {
      // Verification failed
      return res.status(400).json({
        error: 'NIN verification failed',
        details: premblyResponse.data
      });
    }
  } catch (error) {
    // Handle network errors or API errors
    if (error.response) {
      // Prembly API returned an error
      return res.status(error.response.status || 400).json({
        error: 'NIN verification failed',
        details: error.response.data
      });
    } else if (error.request) {
      // Request was made but no response received
      return res.status(500).json({
        error: 'Unable to reach verification service'
      });
    } else {
      // Other errors
      return res.status(500).json({
        error: 'Internal server error',
        message: error.message
      });
    }
  }
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'healthy' });
});

// Start the server
app.listen(PORT, () => {
  console.log(`Fintech wallet creation server running on port ${PORT}`);
  console.log(`POST /api/wallet/create - Create wallet with NIN verification`);
});

